{
var seed = GetInt(parameters, "seed", context.Seed);
var time = GetFloat(parameters, "time", 0f);
var branching = GetFloat(parameters, "branching", 0.5f);
var distortion = GetFloat(parameters, "distortion", 0.5f);
var brightness = GetFloat(parameters, "brightness", 1.0f);
var thickness = GetFloat(parameters, "thickness", 0.03f);
var pixelSize = Math.Max(1, GetInt(parameters, "pixelSize", 1));
var boltColor = GetColor(parameters, "boltColor", System.Windows.Media.Color.FromRgb(180, 200, 255));

var cR = boltColor.R/255f; var cG = boltColor.G/255f; var cB = boltColor.B/255f;
var size = context.TileSize;
var result = new PixelBuffer(size, size);

// Time-driven animation
var animSeed = seed + (int)(time * 9973);

// Generate bolt path using hash-based midpoint displacement
var ptCount = 2;
var ptX = new float[] { (0.2f + HashToUnit(animSeed, 111, 333) * 0.6f) * size, (0.2f + HashToUnit(animSeed + 1, 111, 333) * 0.6f) * size };
var ptY = new float[] { size * 0.05f, size * 0.95f };

var dispScale = distortion * size * 0.35f;
for (var iter = 0; iter < 6; iter++)
{
    var newCount = ptCount * 2 - 1;
    var nx = new float[newCount]; var ny = new float[newCount];
    for (var i = 0; i < ptCount - 1; i++)
    {
        var idx = i * 2;
        nx[idx] = ptX[i]; ny[idx] = ptY[i];
        var hash = HashToUnit(iter * 1000 + i, animSeed + 777, 999);
        nx[idx + 1] = (ptX[i] + ptX[i+1]) * 0.5f + (hash - 0.5f) * dispScale;
        ny[idx + 1] = (ptY[i] + ptY[i+1]) * 0.5f + (hash - 0.5f) * dispScale * 0.4f;
    }
    nx[newCount - 1] = ptX[ptCount - 1]; ny[newCount - 1] = ptY[ptCount - 1];
    ptX = nx; ptY = ny; ptCount = newCount;
    dispScale *= 0.45f;
}

// Draw main bolt - overlap additive blend, no black border
DrawBolt(result, ptX, ptY, ptCount, thickness, pixelSize, cR, cG, cB, brightness, size);

// Branches
var numBranches = (int)(branching * 5);
for (var b = 0; b < numBranches; b++)
{
    var segIdx = (int)(HashToUnit(b * 31 + 7, animSeed + 111, 555) * (ptCount - 2)) + 1;
    segIdx = Math.Clamp(segIdx, 1, ptCount - 2);

    var angle = (HashToUnit(b * 17 + 3, animSeed + 222, 666) - 0.5f) * 2f;
    var len = (0.08f + HashToUnit(b * 23 + 5, animSeed + 333, 777) * 0.18f) * size;
    var dirX = MathF.Cos(angle);
    var dirY = MathF.Sin(angle) * 0.7f + 0.5f;
    var dl = Math.Max(0.001f, MathF.Sqrt(dirX*dirX + dirY*dirY));
    dirX /= dl; dirY /= dl;

    var brCount = 2;
    var brX = new float[] { ptX[segIdx], ptX[segIdx] + dirX * len };
    var brY = new float[] { ptY[segIdx], ptY[segIdx] + dirY * len };
    var bDisp = len * 0.15f;
    for (var iter = 0; iter < 3; iter++)
    {
        var newCount = brCount * 2 - 1;
        var nbx = new float[newCount]; var nby = new float[newCount];
        for (var i = 0; i < brCount - 1; i++)
        {
            var idx = i * 2;
            nbx[idx] = brX[i]; nby[idx] = brY[i];
            var hash2 = HashToUnit(iter * 100 + i, b * 37 + animSeed + 888, 111);
            nbx[idx + 1] = (brX[i] + brX[i+1]) * 0.5f + (hash2 - 0.5f) * bDisp;
            nby[idx + 1] = (brY[i] + brY[i+1]) * 0.5f + (hash2 - 0.5f) * bDisp * 0.4f;
        }
        nbx[newCount - 1] = brX[brCount - 1]; nby[newCount - 1] = brY[brCount - 1];
        brX = nbx; brY = nby; brCount = newCount;
        bDisp *= 0.45f;
    }
    var bBright = brightness * (0.25f + HashToUnit(b, animSeed + 444, 888) * 0.25f);
    DrawBolt(result, brX, brY, brCount, thickness * 0.5f, pixelSize, cR, cG, cB, bBright, size);
}
return result;

void DrawBolt(PixelBuffer buf, float[] xs, float[] ys, int count, float thick, int pxSz, float rr, float gg, float bb, float bright, int sz)
{
    var r2 = Math.Max(1, (int)(thick * sz));
    for (var i = 0; i < count - 1; i++)
    {
        var x1 = xs[i]; var y1 = ys[i];
        var x2 = xs[i+1]; var y2 = ys[i+1];
        var dx = x2 - x1; var dy = y2 - y1;
        var steps = Math.Max(2, (int)MathF.Sqrt(dx*dx + dy*dy));
        for (var s = 0; s <= steps; s++)
        {
            var t = s / (float)steps;
            var px = (int)(x1 + dx * t);
            var py = (int)(y1 + dy * t);
            // Clamp to bounds
            var cpx = Math.Clamp(px, 0, sz - 1);
            var cpy = Math.Clamp(py, 0, sz - 1);
            buf.SetPixel(cpx, cpy, Math.Clamp(rr * bright, 0f, 1f), Math.Clamp(gg * bright, 0f, 1f), Math.Clamp(bb * bright, 0f, 1f), 1f);
            // Inner glow
            if (r2 > 1)
            for (var oy = -r2 + 1; oy <= r2 - 1; oy++)
            for (var ox = -r2 + 1; ox <= r2 - 1; ox++)
            {
                var nx = cpx + ox;
                var ny = cpy + oy;
                if (nx < 0 || nx >= sz || ny < 0 || ny >= sz) continue;
                var d = MathF.Sqrt(ox*ox + oy*oy) / r2;
                var glow = Math.Clamp(1f - d * d, 0f, 1f) * bright * 0.5f;
                buf.SetPixel(nx, ny, Math.Clamp(rr * glow, 0f, 1f), Math.Clamp(gg * glow, 0f, 1f), Math.Clamp(bb * glow, 0f, 1f), 1f);
            }
        }
    }
}
}
